using Microsoft.EntityFrameworkCore;

// Cosmos DB project context — demonstrates EF Core 9 breaking change fixes
// for existing documents using "Discriminator" property and sync queries.

class CosmosContext : DbContext
{
    public DbSet<Session> Sessions => Set<Session>();

    protected override void OnConfiguring(DbContextOptionsBuilder options)
    {
        options.UseCosmos(
            "AccountEndpoint=https://localhost:8081/;AccountKey=placeholder",
            "MyDatabase");
    }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Fix 1: EF Core 9 renamed the default discriminator from "Discriminator"
        // to "$type". Existing documents still use "Discriminator", so we must
        // explicitly preserve the old property name.
        modelBuilder.Entity<Session>().HasDiscriminator<string>("Discriminator");

        // Fix 2: EF Core 9 changed `id` to contain only the key value (e.g. "123")
        // instead of "EntityType|KeyValue" (e.g. "Session|123"). Existing documents
        // use the old compound format. Preserve it so point-reads still work.
        modelBuilder.Entity<Session>().HasRootDiscriminatorInJsonId(true);
    }
}

class Session
{
    public string Id { get; set; } = null!;
    public string Title { get; set; } = null!;
}

// Fix 3: The Cosmos DB provider no longer supports synchronous I/O.
// Methods like ToList() and SaveChanges() now throw.
// All queries and writes must use async equivalents.
//
// BEFORE (throws in EF Core 9):
//   var sessions = db.Sessions.Where(s => s.Title == "Keynote").ToList();
//   db.SaveChanges();
//
// AFTER:
//   var sessions = await db.Sessions.Where(s => s.Title == "Keynote").ToListAsync();
//   await db.SaveChangesAsync();

